"""
MKT Christ Layer — Ecclesiastes chapters 1–4 (comprehensive)
Run: python3 scripts/zc-christ-ecclesiastes-1-4.py

82 verses: ch1=18, ch2=26, ch3=22, ch4=16
Christological lens: hevel as post-fall condition Christ came to break;
eternity in the heart as the longing Christ fulfills; the Comforter;
the one who ascends; the poor-wise-youth who goes to throne.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DATA = {
  "1": {
    "1": "<p>A shadow: Qohelet, the Assembler/Preacher, speaks. The title <em>qohelet</em> derives from <em>qahal</em> (assembly, congregation) — the one who gathers or addresses the assembly. Christ is the ultimate Preacher-Teacher who gathers his assembly (Matt 5:1: he opened his mouth and taught; Luke 4:18-19: the Spirit of the Lord is upon me to preach). But where Qohelet gathers to deliver a verdict of vanity, Christ gathers to announce the kingdom — not 'all is hebel' but 'blessed are you.' The book's opening word signals the whole: a wisdom preacher addressing God's people about the nature of human existence.</p>",
    "2": "<p>A type: 'Vanity of vanities, all is vanity.' The Hebrew <em>hevel</em> (breath, vapor) is the diagnosis of the post-fall condition of creation — everything human striving builds dissolves like breath in cold air. Paul identifies this directly in Romans 8:20: 'the creation was subjected to futility [<em>mataiotes</em>, the LXX word for <em>hevel</em>] not willingly, but because of him who subjected it, in hope.' The <em>hevel</em>-condition is the consequence of the fall; Christ's work is the answer. The 'not in vain' of 1 Corinthians 15:58 — 'your labor in the Lord is not in vain' — is the direct reversal of 'all is vanity': the resurrection of Christ breaks the <em>hevel</em>-cycle. Qohelet's diagnosis is accurate; the cure is what he cannot yet see.</p>",
    "3": "<p>A theme: 'What does man gain [<em>yitron</em>] from all his toil at which he toils under the sun?' <em>Yitron</em> is a commercial term — surplus, profit left over after expenses. Qohelet's question is: what is the net gain of a human life? His answer will be 'nothing.' Paul answers from the other side of the resurrection: 'your labor in the Lord is not in vain' (1 Cor 15:58); 'to live is Christ, and to die is gain' (Phil 1:21). The <em>yitron</em>-question Qohelet asks, Christ answers by being himself the profit: in him, labor has eternal weight. The 'under the sun' qualifier matters — all toil within the merely earthly frame produces no lasting surplus. Christ breaks the frame.</p>",
    "4": "<p>A shadow: 'A generation goes, and a generation comes, but the earth remains forever.' The endless cycle of human generations without permanence — what one generation builds, the next inherits and then loses. Hebrews 1:10-12 addresses this directly, quoting Psalm 102 of Christ: 'You, Lord, laid the foundation of the earth in the beginning, and the heavens are the work of your hands; they will perish, but you remain; they will all wear out like a garment... but you are the same, and your years will have no end.' The creation that 'remains forever' by Qohelet's observation does not actually remain — even it will perish. Only Christ remains unchanged through all the generational cycling.</p>",
    "5": "<p>A shadow: 'The sun rises, and the sun sets, and hastens to its place where it rises.' The sun's endless cycle — the image of relentless, purposeless repetition. John 8:12: 'I am the light of the world. Whoever follows me will not walk in darkness, but will have the light of life.' The sun Qohelet observes cycling without purpose becomes in Christ the image of the true light who does not cycle into darkness: Revelation 22:5 — 'night will be no more. They will need no light of lamp or sun, for the Lord God will be their light.' The solar cycle is the creation-image for <em>hevel</em>; Christ is the light that ends the cycle.</p>",
    "6": "<p>A shadow: 'The wind goes toward the south and turns to the north; around and around goes the wind, and on its circuits the wind returns.' The wind's purposeless circling reinforces the vanity-of-cycles motif. But Christ uses the wind as the image of the Spirit's sovereign, purposive work: 'The wind blows where it wishes, and you hear its sound, but you do not know where it comes from or where it goes. So it is with everyone who is born of the Spirit' (John 3:8). The wind that Qohelet observes cycling in meaningless circuits is reframed by Christ as the image of the Spirit's free and regenerating movement — the same wind, but now purposive and life-giving rather than vanity-illustrating.</p>",
    "7": "<p>A shadow: 'All streams run to the sea, yet the sea is not full; to the place where the streams flow, there they flow again.' The unfillable sea — the image of unsatisfied longing, the human condition of desire that nothing satisfies. Revelation 22:1 presents the eschatological fulfillment: 'Then the angel showed me the river of the water of life, bright as crystal, flowing from the throne of God and of the Lamb.' The sea that is never full in Qohelet's observation becomes in the new creation the river of life that flows from the Lamb's throne — not an endless unsatisfied cycle, but a perpetual outflow of life. John 4:14: 'the water that I will give him will become in him a spring of water welling up to eternal life.'</p>",
    "8": "<p>A direct connection: 'All things are full of weariness; a man cannot utter it; the eye is not satisfied with seeing, nor the ear filled with hearing.' The unsatisfied eye and ear — no earthly thing can fill the human capacity for seeing and hearing. Christ's answer is direct: 'I am the bread of life; whoever comes to me shall not hunger, and whoever believes in me shall never thirst' (John 6:35). The eye not satisfied with seeing is satisfied when it sees Christ (John 14:9: 'Whoever has seen me has seen the Father'). The ear not filled with hearing is filled by his words (John 6:68: 'Lord, to whom shall we go? You have the words of eternal life'). What no earthly thing could fill, Christ fills.</p>",
    "9": "<p>A type: 'What has been is what will be, and what has been done is what will be done, and there is nothing new under the sun.' The no-novelty principle — history as endless recurrence with no new thing. 2 Corinthians 5:17: 'Therefore, if anyone is in Christ, he is a new creation. The old has passed away; behold, the new has come.' Christ is the absolute exception to the nothing-new principle: his resurrection is the first genuinely new thing since the creation — a body that has passed through death and emerged transformed, not merely resuscitated. The new creation is not a repetition of the old. Revelation 21:5: 'Behold, I am making all things new.' The thing Qohelet declares impossible — something genuinely new — is precisely what Christ brings.</p>",
    "10": "<p>A shadow: 'Is there a thing of which it is said, See, this is new? It has been already in the ages before us.' The skeptic's challenge to novelty claims — everything that seems new has already existed before. Christ's response to this entire trajectory is the resurrection, which is categorically unprecedented: no one in history had ever been raised with a glorified, deathless body. 1 Corinthians 15:20: 'But in fact Christ has been raised from the dead, the firstfruits of those who have fallen asleep.' The firstfruits language signals absolute novelty: a first-of-its-kind event. The 'already been before us' claim is the very thing the resurrection refutes.</p>",
    "11": "<p>A shadow: 'There is no remembrance of former things, nor will there be any remembrance of things that are to come among those who come after.' The oblivion of human memory — nothing is permanently remembered, everything fades. Isaiah 43:18-19: 'Remember not the former things, nor consider the things of old. Behold, I am doing a new thing; now it springs forth, do you not perceive it?' And Revelation 21:4: 'He will wipe away every tear from their eyes, and death shall be no more, neither shall there be mourning, nor crying, nor pain anymore, for the former things have passed away.' In the new creation, what passes away is not the memory of the righteous (Ps 112:6: 'the righteous will be remembered forever') but the former sufferings — a reversal of Qohelet's amnesia principle.</p>",
    "12": "<p>A shadow: 'I the Preacher have been king over Israel in Jerusalem.' Qohelet identifies himself as the royal wisdom-seeker. Christ is the ultimate royal wisdom-seeker — not an earthly king exploring wisdom, but Wisdom himself made flesh and becoming the king who has 'searched out by wisdom all that is done under heaven' (1:13), and whose verdict is not vanity but 'I am the way, and the truth, and the life' (John 14:6). The king-wisdom figure that Solomon represents is a type of Christ the king-Wisdom (1 Cor 1:24: 'Christ the power of God and the wisdom of God').</p>",
    "13": "<p>A theme: 'And I applied my heart to seek and to search out by wisdom all that is done under heaven. It is an unhappy business that God has given to the children of man to be busy with.' The wisdom-quest applied to all human activity — Qohelet's comprehensive investigation. Colossians 2:3: 'In Christ are hidden all the treasures of wisdom and knowledge.' What Qohelet sought by investigation, Christ is by nature: the one in whom all wisdom is hidden. The 'unhappy business' of wisdom-seeking under the sun becomes in Christ the joyful discovery that wisdom has come down and made itself accessible. John 14:6: 'I am the truth' — the search is over.</p>",
    "14": "<p>A theme: 'I have seen everything that is done under the sun, and behold, all is vanity and a striving after wind.' The conclusion of the wisdom-survey: all earthly achievement and knowledge produces only vanity. John 6:27: 'Do not work for the food that perishes, but for the food that endures to eternal life, which the Son of Man will give to you.' The labor that produces only vanity (striving after wind) is contrasted with labor directed toward Christ, who gives the food that endures. The shift from 'all is vanity' to 'labor in the Lord is not in vain' (1 Cor 15:58) depends entirely on whether the labor is 'under the sun' (earthly frame only) or 'in the Lord' (resurrection frame).</p>",
    "15": "<p>A type pointing to prophetic fulfillment: 'What is crooked cannot be made straight, and what is lacking cannot be counted.' Qohelet's statement of the limits of human wisdom — there are disorders that wisdom cannot correct. Isaiah 40:4 and Luke 3:5 announce the opposite: 'every valley shall be filled, and every mountain and hill shall be made low, and the crooked shall become straight, and the rough places shall become level ways.' The impossible that Qohelet declares — making crooked things straight — is precisely what John the Baptist announces as the work of Christ's coming. The theological claim of the gospel is that what human wisdom cannot accomplish, God's intervention through Christ can and will.</p>",
    "16": "<p>A shadow: 'I said in my heart, 'I have acquired great wisdom, surpassing all who were before me over Jerusalem, and my heart has had great experience of wisdom and knowledge.'' Solomon's claim to surpassing wisdom — the zenith of human wisdom achievement. Matthew 12:42: 'The queen of the South came from the ends of the earth to hear the wisdom of Solomon, and behold, something greater than Solomon is here.' Christ's claim to be greater than Solomon — the very pinnacle Qohelet invokes — positions him as the one who stands beyond the entire wisdom-competition frame. What Solomon achieved was the maximum of human wisdom; Christ is divine wisdom in person (1 Cor 1:24).</p>",
    "17": "<p>A shadow: 'And I applied my heart to know wisdom and to know madness and folly. I perceived that this also is but a striving after wind.' Even the pursuit of wisdom itself turns out to be vanity — the ultimate irony of the wisdom-quest. 1 Corinthians 3:19: 'the wisdom of this world is folly with God.' Paul takes the Qohelet diagnosis and applies it theologically: earthly wisdom that does not reckon with God is foolishness. The inversion of Christ's cross becomes the new epistemology: 'the foolishness of God is wiser than men' (1 Cor 1:25). The wisdom Qohelet found to be striving after wind is precisely what Paul identifies as the world's pseudo-wisdom; the real wisdom is the crucified Christ.</p>",
    "18": "<p>A shadow: 'For in much wisdom is much vexation, and he who increases knowledge increases sorrow.' The wisdom-grief formula — the more Qohelet knows, the more he suffers from knowing. Isaiah 53:3: 'He was despised and rejected by men, a man of sorrows and acquainted with grief.' Christ, the fullness of wisdom and knowledge (Col 2:3), is also the man of sorrows — the one who, knowing everything, bore the maximum of grief. The Qohelet formula points to the incarnation: to enter fully into human wisdom is to enter fully into human grief, which is exactly what the Son of God did. The wisdom-sorrow that Qohelet observes is fulfilled in the one who is both the fullness of wisdom and the bearer of human sorrow.</p>"
  },
  "2": {
    "1": "<p>A shadow: 'I said in my heart, 'Come now, I will test you with pleasure; enjoy yourself.' But behold, this also was vanity.' The self-experiment with pleasure — testing whether enjoyment can answer the vanity-question. Hebrews 4:15: 'we have a high priest who in every respect has been tempted as we are, yet without sin.' Christ underwent the full range of human temptation (including the temptation to satisfy himself through pleasure, cf. Luke 4:1-13) without falling. Where Qohelet discovers that pleasure is vanity, Christ demonstrates that the proper response to temptation is not indulgence but faithfulness — 'man shall not live by bread alone' (Luke 4:4).</p>",
    "2": "<p>A shadow: 'I said of laughter, 'It is mad,' and of pleasure, 'What use is it?'' Qohelet's dismissal of laughter as madness and pleasure as purposeless. Luke 6:25: 'Woe to you who laugh now, for you will mourn and weep.' Christ's woe to hollow laughter stands with Qohelet's verdict. But the NT also promises the inversion: John 16:22: 'you will be sorrowful, but your sorrow will turn into joy... your joy no one will take from you.' The empty laughter Qohelet dismisses contrasts with the full joy Christ gives — not the laughter that is mad but the joy that is solid and permanent.</p>",
    "3": "<p>A shadow: 'I searched with my heart how to cheer my body with wine — my heart still guiding me with wisdom — and how to lay hold on folly, till I might see what was good for the children of man to do under heaven during the few days of their life.' Qohelet's search for legitimate pleasure through wine. John 2:1-11: Christ transforms water into wine at the wedding — not ending the pleasure of wine but providing better wine, a sign of the kingdom's abundance. But more: John 6:53-56 reframes the search entirely — the flesh and blood of Christ are the true food and drink, the thing Qohelet was searching for when he reached for wine. The experiment with wine points toward the one who gives wine as a sign of his blood poured out for the joy of the world.</p>",
    "4": "<p>A shadow: 'I made great works. I built houses and planted vineyards for myself.' Solomon as the great builder — the human capacity for construction pushed to its maximum. The ultimate Builder is Christ, who builds what will not fail: 'I will build my church, and the gates of hell shall not prevail against it' (Matt 16:18). And the eschatological construction project: Revelation 21:1-2 — the new Jerusalem coming down from God, prepared as a bride. The city that Qohelet builds on earth and then leaves behind becomes in Christ the city that descends from heaven and endures forever.</p>",
    "5": "<p>A shadow: 'I made myself gardens and parks, and planted in them all kinds of fruit trees.' The garden-paradise that Solomon constructs — the attempt to recreate Eden through human ingenuity. The trajectory of Scripture runs: Eden lost (Gen 3) → wilderness (Sinai) → promised land → the perfect garden of Song of Solomon 4:12-16 → the new creation's garden-city (Rev 22:1-5). Christ is the one who reopens the gate of paradise: 'today you will be with me in paradise' (Luke 23:43). The garden that Qohelet builds with his own hands anticipates the garden Christ reopens at the cross and perfects in the new creation.</p>",
    "6": "<p>A shadow: 'I made myself pools from which to water the forest of growing trees.' The water-provision for the constructed garden — Solomon making himself the source of water for his project. Jesus at the well: 'whoever drinks of the water that I will give him will never be thirsty again. The water that I will give him will become in him a spring of water welling up to eternal life' (John 4:14). The pools Qohelet digs to water his gardens are an image of the human attempt to secure the life-giving resource; Christ offers the water that is inexhaustible and self-replenishing, not stored in pools but welling up within.</p>",
    "7": "<p>A shadow: 'I bought male and female slaves, and had slaves who were born in my house. I had also great possessions of herds and flocks, more than any who had been before me in Jerusalem.' The accumulation of possessions — Solomon at the peak of material wealth. 2 Corinthians 8:9: 'though he was rich, yet for your sake he became poor, so that you by his poverty might become rich.' Christ's voluntary impoverishment is the inversion of Qohelet's wealth-accumulation. Where Solomon accumulated everything and found it vanity, Christ gave up everything and in that giving secured an imperishable inheritance (1 Pet 1:4) for those who were impoverished.</p>",
    "8": "<p>A shadow: 'I also gathered for myself silver and gold and the treasure of kings and provinces.' The treasury-accumulation — the maximum of material wealth. 2 Corinthians 8:9: Christ 'though he was rich, yet for your sake he became poor.' Colossians 2:3: 'in Christ are hidden all the treasures of wisdom and knowledge.' The silver and gold Qohelet gathers and will leave behind are the shadow of the imperishable treasure Christ is and gives. Matthew 6:19-20: 'Do not lay up for yourselves treasures on earth, where moth and rust destroy... but lay up for yourselves treasures in heaven.' The Qohelet experiment demonstrates why earthly treasure cannot satisfy; Christ provides the alternative.</p>",
    "9": "<p>A shadow: 'So I became great and surpassed all who were before me in Jerusalem. Also my wisdom remained with me.' Solomon at his zenith — the human greatness that has no peer. Philippians 2:9: 'Therefore God has highly exalted him and bestowed on him the name that is above every name.' But the path to Christ's exaltation is through humiliation, not accumulation — precisely the opposite of Qohelet's ascending greatness-narrative. The greatness that Christ achieves through self-giving endures; the greatness Qohelet achieves through accumulation passes away. Paul's 'therefore God highly exalted him' follows the cross, not the treasury.</p>",
    "10": "<p>A shadow: 'And whatever my eyes desired I did not keep from them. I kept my heart from no pleasure, for my heart found pleasure in all my toil, and this was my reward for all my toil.' The unrestrained self-indulgence of the pleasure-experiment. Hebrews 4:15: 'we do not have a high priest who is unable to sympathize with our weaknesses, but one who in every respect has been tempted as we are, yet without sin.' Where Qohelet withheld nothing from himself, Christ — facing every temptation — withheld himself from sin. The contrast is not asceticism vs. pleasure but faithfulness vs. indulgence. Christ's 'yet without sin' is what makes his high priesthood effective where Qohelet's experiment failed.</p>",
    "11": "<p>A theme: 'Then I considered all that my hands had done and the toil I had expended in doing it, and behold, all was vanity and a striving after wind, and there was nothing to be gained under the sun.' The comprehensive verdict on human achievement: all vanity. 1 Corinthians 15:58: 'Therefore, my beloved brothers, be steadfast, immovable, always abounding in the work of the Lord, knowing that in the Lord your labor is not in vain.' The transformation from Qohelet's 'all is vanity' to Paul's 'not in vain' is entirely dependent on the resurrection of Christ. The 'under the sun' qualifier in Qohelet's verdict signals the limitation: within the merely temporal frame, it is true. But Christ breaks the temporal frame.</p>",
    "12": "<p>A shadow: 'So I turned to consider wisdom and madness and folly, for what can the man do who comes after the king? Only what has already been done.' The wisdom-madness-folly survey — Qohelet investigating the full range of human mental life. 1 Corinthians 1:18-25: 'the word of the cross is folly to those who are perishing, but to us who are being saved it is the power of God... God chose what is foolish in the world to shame the wise.' Paul inverts the wisdom-folly hierarchy in light of the cross: what seems wisdom (Qohelet's rational investigation) cannot reach what only revelation reveals; what seems folly (the cross) is actually the wisdom of God.</p>",
    "13": "<p>A direct connection: 'Then I saw that there is more gain in wisdom than in folly, as there is more gain in light than in darkness.' The light-exceeds-darkness observation — even Qohelet recognizes that wisdom has relative advantage. John 1:5: 'The light shines in the darkness, and the darkness has not overcome it.' John 8:12: 'I am the light of the world. Whoever follows me will not walk in darkness, but will have the light of life.' What Qohelet observes as a general truth — light exceeds darkness — Christ claims as a personal identity. The relative advantage of light over darkness becomes in Christ the absolute: 'the darkness has not overcome it.'</p>",
    "14": "<p>A direct connection: 'The wise person has his eyes in his head, but the fool walks in darkness. And yet I perceived that the same event happens to all of them.' The sight-blindness contrast — the wise man uses his eyes; the fool is in darkness. John 8:12: 'I am the light of the world. Whoever follows me will not walk in darkness, but will have the light of life.' Christ addresses not just the preference for wisdom over folly but the source of the light that enables sight. The 'same event happens to all' — both wise and fool die — is the limitation Qohelet sees but cannot transcend; the resurrection is the event that breaks the 'same fate for all' principle.</p>",
    "15": "<p>A type: 'Then I said in my heart, 'What happens to the fool will happen to me also. Why then have I been so very wise?' And I said in my heart that this also is vanity.' Qohelet's recognition that the same fate overtakes the wise as the fool — death equalizes. Hebrews 2:14-17: 'Since therefore the children share in flesh and blood, he himself likewise partook of the same things, that through death he might destroy the one who has the power of death... Therefore he had to be made like his brothers in every respect.' Christ deliberately shared the fate of the fool and the wise alike — mortality — in order to destroy death from the inside. The 'same event happens to all' is what Christ entered, and in entering he undid it.</p>",
    "16": "<p>A shadow: 'For of the wise as of the fool there is no enduring remembrance, seeing that in the days to come all will have been long forgotten. How the wise dies just like the fool!' The amnesia that overtakes even the wise — no permanent memorial. John 14:26: 'the Helper, the Holy Spirit, whom the Father will send in my name, he will teach you all things and bring to your remembrance all that I have said to you.' The Spirit's role of 'bringing to remembrance' counters the amnesia principle. And Psalm 112:6, cited in the NT tradition: 'the righteous will be remembered forever.' What Qohelet sees as the universal amnesia-fate is reversed for those in Christ, whose words and deeds are preserved by the Spirit.</p>",
    "17": "<p>A direct allusion: 'So I hated life, because what is done under the sun was grievous to me, for all is vanity and a striving after wind.' Qohelet's life-hatred — the nadir of the wisdom experiment. Mark 14:34: 'My soul is very sorrowful, even to death' (Gethsemane). Matthew 26:38: 'remain here, and watch with me.' Christ in Gethsemane enters the depth of grief that Qohelet describes — the soul overwhelmed by the weight of existence. But where Qohelet's life-hatred produces despair, Christ's agony produces surrender: 'not my will, but yours, be done' (Luke 22:42). The pattern: enter the grief fully, then surrender it to the Father.</p>",
    "18": "<p>A theme: 'I hated all my toil in which I toil under the sun, seeing that I must leave it to the man who comes after me.' The grief of leaving accumulated toil to an unknown heir — the pointlessness of accumulation. Galatians 4:4: 'when the fullness of time had come, God sent forth his Son.' The 'fullness of time' means that all the toil of history — the generations of patriarchs, judges, kings, prophets — had its accumulation directed toward a specific moment. Christ does not leave his work to an uncertain heir; he gives it to his church through the Spirit, and the inheritance is imperishable (1 Pet 1:3-5). The toil that Qohelet leaves to an unknown stranger, Christ bequeaths through deliberate covenant.</p>",
    "19": "<p>A shadow: 'and who knows whether he will be wise or a fool? Yet he will be master of all for which I toiled and used my wisdom under the sun. This also is vanity.' The unknown-heir problem — all accumulated wisdom will be managed by someone who may be a fool. Romans 8:28: 'we know that for those who love God all things work together for good, for those who are called according to his purpose.' The uncertainty Qohelet feels about what comes after him is replaced in Christ's framework by a purposive God who works all things toward the good. The apparently random distribution of wisdom's fruits is governed by the one who 'works all things according to the counsel of his will' (Eph 1:11).</p>",
    "20": "<p>A shadow: 'So I turned about and gave my heart up to despair over all the toil of my labors under the sun.' The despair that follows the recognition of toil's futility — Qohelet at his lowest. John 12:27: 'Now is my soul troubled. And what shall I say? 'Father, save me from this hour'? But for this purpose I have come to this hour.' Christ's 'troubled soul' before the cross is the weight of bearing the full accumulation of human toil-and-vanity. He enters Qohelet's despair, carries it to the cross, and through the resurrection transforms despair into 'it is finished' (John 19:30) — the toil accomplished, not abandoned.</p>",
    "21": "<p>A shadow: 'because sometimes a person who has toiled with wisdom and knowledge and skill must leave everything to be enjoyed by someone who did not toil for it. This also is vanity and a great evil.' The injustice of leaving earned inheritance to an unearned heir. John 17:22, 24: 'The glory that you have given me I have given to them... Father, I desire that they also, whom you have given me, may be with me where I am, to see my glory.' Christ gives to his disciples — who did not earn it — the glory that he earned through his toil and suffering. The injustice Qohelet laments (earning it, another enjoys it) is reversed in the gift of grace: Christ earned it, his people receive it — not as injustice but as the deliberate generosity of the one who toiled for others.</p>",
    "22": "<p>A theme: 'For what does man get from all the toil and striving of heart with which he labors under the sun?' The <em>yitron</em>-question returned — what is the net gain? 1 Corinthians 15:58: 'your labor in the Lord is not in vain.' The answer to Qohelet's question depends entirely on the frame: under the sun (the purely temporal), the net gain is zero. In the Lord (the resurrection frame), labor has eternal weight. The question Qohelet asks is the right question; the answer he cannot yet supply is given by the one who rose from the dead and calls people to labor in his name.</p>",
    "23": "<p>A shadow: 'For all his days are full of sorrow, and his work is a vexation. Even in the night his heart does not rest. This also is vanity.' The sleepless grief of the toiling person — sorrow by day, no rest by night. Isaiah 53:3-4: 'He was despised and rejected by men, a man of sorrows and acquainted with grief... Surely he has borne our griefs and carried our sorrows.' Christ bears the cumulative weight of human sorrow — including the sorrow Qohelet describes — in his passion. Matthew 26:36-46: the sleepless night in Gethsemane, sweating blood, is the maximum of sorrow-with-no-rest-by-night. He entered the condition fully in order to bear it away.</p>",
    "24": "<p>A direct connection: 'There is nothing better for a person than that he should eat and drink and find enjoyment in his toil. This also, I saw, is from the hand of God.' Qohelet's positive conclusion: enjoyment is God's gift. John 6:53-55: 'unless you eat the flesh of the Son of Man and drink his blood, you have no life in you. Whoever feeds on my flesh and drinks my blood has eternal life, and I will raise him up on the last day.' Christ takes the 'eat and drink' that Qohelet commends as God's best gift and transforms it into the Eucharist — the eating and drinking that gives eternal life. What Qohelet sees as the highest good God gives becomes in Christ the vehicle for the highest good of all: communion with the Son of God.</p>",
    "25": "<p>A direct connection: 'for apart from him who can eat or who can have enjoyment?' Nothing is truly enjoyed apart from God — Qohelet's theological claim about the source of enjoyment. John 6:27, 35: 'Do not work for the food that perishes, but for the food that endures to eternal life, which the Son of Man will give to you... I am the bread of life; whoever comes to me shall not hunger, and whoever believes in me shall never thirst.' Christ is both the one who gives the food and the food itself — the 'apart from whom nothing is enjoyed' of Ecclesiastes becomes the 'I am the bread of life' of the gospel. The theological grammar is the same: all true enjoyment is from and through God; in Christ, that God has become accessible.</p>",
    "26": "<p>A direct allusion: 'For to the one who pleases him God has given wisdom and knowledge and joy, but to the sinner he has given the business of gathering and collecting, only to give to one who pleases God. This also is vanity and a striving after wind.' Divine favor as the source of wisdom, knowledge, and joy. Matthew 3:17; 17:5: 'This is my beloved Son, with whom I am well pleased.' Christ is the one whom the Father explicitly pleases — and to him, by right, belongs all wisdom, knowledge, and joy. The one who pleases God in Ecclesiastes 2:26 is first and perfectly Christ; believers enter into this pleased-with status through union with him (Eph 1:6: 'he has blessed us in the Beloved'). The distribution of wisdom to 'the one who pleases him' finds its ultimate referent in the Son in whom the Father is well pleased.</p>"
  },
  "3": {
    "1": "<p>A direct allusion: 'For everything there is a season, and a time for every matter under heaven.' The time-for-everything principle — creation ordered by divinely appointed seasons. Galatians 4:4: 'But when the fullness of time had come [<em>to pleroma tou chronou</em>], God sent forth his Son, born of woman, born under the law.' The 'fullness of time' is the decisive appointed-time that governs all other appointed times: there was a time for everything, and when the appointed time arrived, the Son entered the sequence. The entire temporal ordering Qohelet surveys had been moving toward this moment. Ecclesiastes 3:1 is the theological premise; Galatians 4:4 is its fulfillment-statement.</p>",
    "2": "<p>A type: 'a time to be born, and a time to die; a time to plant, and a time to pluck up what is planted.' The birth-and-death pairing within the created order. John 12:23-24: 'The hour has come for the Son of Man to be glorified. Truly, truly, I say to you, unless a grain of wheat falls into the earth and dies, it remains alone; but if it dies, it bears much fruit.' Christ's birth-and-death follows the Qohelet time-sequence, but with a crucial addition: the dying produces fruit rather than vanity. The 'time to die' that Qohelet observes as simply the rhythm of creation becomes in Christ the moment of maximum fruitfulness — the death that is actually a planting.</p>",
    "3": "<p>A shadow: 'a time to kill, and a time to heal; a time to break down, and a time to build up.' The healing-time in the Qohelet sequence. Luke 4:18-19: 'He has sent me to proclaim liberty to the captives and recovering of sight to the blind, to set at liberty those who are oppressed, to proclaim the year of the Lord's favor.' Christ's announcement of his ministry is entirely in the register of healing and building up — the two positive items in Qohelet's pairing. The accumulated broken-down, killed, wounded condition of humanity in the fall-season is addressed in the healing ministry of Christ, who enters the 'time to heal' and the 'time to build up.'</p>",
    "4": "<p>A shadow: 'a time to weep, and a time to laugh; a time to mourn, and a time to dance.' The mourning-to-dancing sequence that creation embeds in time. John 11:35: 'Jesus wept' — he entered the mourning-time with those who mourned Lazarus, not bypassing grief but entering it. John 20:20: 'the disciples were glad when they saw the Lord' — the resurrection produces the dancing-time. The Qohelet time-sequence of mourning and dancing is lived out by Christ: he wept at the tomb, entered the death himself, and on the third day the disciples saw him and rejoiced. The time-pattern is not meaningless cycling; in Christ it has a one-directional resolution: mourning to joy.</p>",
    "5": "<p>A shadow: 'a time to cast away stones, and a time to gather stones together; a time to embrace, and a time to refrain from embracing.' The refraining-from-embrace is the unusual item. John 20:17: 'Do not cling to me, for I have not yet ascended to the Father; but go to my brothers and say to them, 'I am ascending to my Father and your Father.'' The risen Christ instructing Mary not to cling is the 'time to refrain from embracing' — not a withdrawal of love but the transition to a new mode of presence. The embrace-and-refrain rhythm in Qohelet finds its fulfillment in the resurrection appearances that are preparing the disciples for the Spirit's mode of Christ's presence.</p>",
    "6": "<p>A shadow: 'a time to seek, and a time to lose; a time to keep, and a time to cast away.' The seeking-time. Luke 15 (the three parables of the lost): the shepherd seeking the lost sheep, the woman seeking the lost coin, the father running to receive the returning son. Christ as the one who enters the 'time to seek' with maximum intentionality — 'the Son of Man came to seek and to save the lost' (Luke 19:10). The Qohelet time-for-seeking is the temporal structure within which the seeking God operates; Jesus embodies that divine seeking in his ministry.</p>",
    "7": "<p>A shadow: 'a time to tear, and a time to sew; a time to keep silence, and a time to speak.' The tearing-and-sewing. Mark 15:38: 'the curtain of the temple was torn in two, from top to bottom.' The tearing of the temple curtain at Christ's death is the definitive 'time to tear' — the barrier between God and humanity torn open. The silence is also Christological: Matthew 26:63; 27:12-14 — Jesus remained silent before his accusers, fulfilling Isaiah 53:7: 'he opened not his mouth.' The time-for-silence and the time-for-speech are both embodied in Christ's passion.</p>",
    "8": "<p>A direct connection: 'a time to love, and a time to hate; a time for war, and a time for peace.' The love-time. John 15:13: 'Greater love has no one than this, that someone lay down his life for his friends.' Christ's death is the definitive 'time to love' — the moment in the temporal sequence when the love of God was maximally expressed. Romans 5:8: 'God shows his love for us in that while we were still sinners, Christ died for us.' The time-for-love that Qohelet includes in the creation's temporal rhythm is fulfilled in the event of the cross — the appointed time when love achieved its maximum expression.</p>",
    "9": "<p>A theme: 'What gain has the worker from his toil?' The <em>yitron</em>-question again. 1 Corinthians 15:58: 'your labor in the Lord is not in vain.' The answer to the toil-question appears twice in Ecclesiastes (1:3 and 3:9) and each time Paul's answer is the same: the resurrection transforms the zero-gain equation. The question recurs because it is the book's central question; its answer requires the resurrection to be given.</p>",
    "10": "<p>A shadow: 'I have seen the business that God has given to the children of man to be busy with.' The 'business God has given' — the creational task given to humanity. John 9:4: 'We must work the works of him who sent me while it is day; night is coming, when no one can work.' Christ takes the 'business God has given' language and applies it to his own mission: he is the one who does the Father's work while the time remains. The Qohelet phrase 'business God has given to the children of man' becomes in Christ 'the works of him who sent me' — the task is divinely assigned and has its own appointed time.</p>",
    "11": "<p>A direct connection: 'He has made everything beautiful in its time. He has also put eternity into man's heart, yet so that he cannot find out what God has done from the beginning to the end.' The eternity-in-the-heart — the deepest anthropological observation in the book. John 14:6: 'I am the way, and the truth, and the life. No one comes to the Father except through me.' The eternity that God has placed in the human heart as an unfillable longing is answered by Christ, who is himself eternal life (1 John 5:20: 'This is the true God and eternal life'). What Qohelet observes as the human capacity for eternity that nothing earthly can fill, Christ declares himself to be the content of. Colossians 1:27: 'Christ in you, the hope of glory.'</p>",
    "12": "<p>A theme: 'I perceived that there is nothing better for them than to be joyful and to do good as long as they live.' The joy-and-good-works prescription. John 15:11: 'These things I have spoken to you, that my joy may be in you, and that your joy may be full.' Christ promises not merely joy as an abstract good but his own joy — the joy that the eternal Son has in the Father — transplanted into the believer. The Qohelet prescription for joy (be joyful; do good) is the wisdom-tradition form of what Christ calls his disciples to; the source and quality of the joy is transformed in Christ from a choice to a gift.</p>",
    "13": "<p>A direct allusion: 'also that everyone should eat and drink and take pleasure in his toil — this is God's gift.' The eat-and-drink-and-enjoy formula as God's gift. John 6:53-56: 'For my flesh is true food, and my blood is true drink... Whoever feeds on my flesh and drinks my blood abides in me, and I in him.' The Eucharist is the transformation of the Qohelet eat-and-drink pattern from its natural form into its sacramental fulfillment. The 'God's gift' of eating and drinking in Ecclesiastes becomes the gift of Christ's body and blood — the gift of God in its most concentrated form. 'This is God's gift' and 'this is my body given for you' are linked across the canon.</p>",
    "14": "<p>A direct connection: 'I perceived that whatever God does endures forever; nothing can be added to it, nor anything taken from it. God has done it, so that people fear before him.' The permanence of God's work — whatever he does stands. Hebrews 13:8: 'Jesus Christ is the same yesterday and today and forever.' John 1:1: 'In the beginning was the Word, and the Word was with God, and the Word was God.' Christ is the eternal one who does permanent work; what Qohelet observes as the general principle (God's work endures), Christ embodies personally. The resurrection is the irreversible act of God — the permanent work that 'nothing can be added to, nor anything taken from.'</p>",
    "15": "<p>A direct connection: 'That which is, already has been; that which is to be, already has been; and God seeks out what has been driven away.' 'God seeks out what has been driven away' is the most explicit statement in the wisdom literature of the seeking God. Luke 15:4-7 (the lost sheep): 'What man of you, having a hundred sheep, if he has lost one of them, does not leave the ninety-nine in the open country, and go after the lost one until he finds it?' Luke 15:11-32 (the prodigal son): the father runs to meet the returning son. Christ's three lost-parables in Luke 15 are the definitive 'God seeks out what has been driven away' — they are the narrative expansion of Ecclesiastes 3:15b. The God who seeks the driven-away becomes the shepherd, the woman, and the father.</p>",
    "16": "<p>A shadow: 'Moreover, I saw under the sun that in the place of justice, even there was wickedness, and in the place of righteousness, even there was wickedness.' Justice corrupted at its very seat — the perversion of the judicial system. John 18:28-19:16: the trial of Jesus is the supreme instance of wickedness in the place of justice — the most unjust trial in history, conducted against the just one. The verdict of the Roman governor ('I find no guilt in him,' John 18:38; 19:4, 6) was publicly stated three times; then the unjust sentence was carried out. Qohelet's observation about wickedness in the place of justice is maximally exemplified in the passion narrative.</p>",
    "17": "<p>A direct connection: 'I said in my heart, God will judge the righteous and the wicked, for there is a time for every matter and for every work.' God as the ultimate judge who corrects earthly injustice. John 5:22, 27: 'The Father judges no one, but has given all judgment to the Son... And he has given him authority to execute judgment, because he is the Son of Man.' Christ is the appointed judge whom Qohelet points to when he says 'God will judge.' Acts 17:31: 'he has fixed a day on which he will judge the world in righteousness by a man whom he has appointed.' The judge Qohelet anticipates is identified in the NT as the risen Christ.</p>",
    "18": "<p>A shadow: 'I said in my heart with regard to the children of man that God is testing them that they may see that they themselves are but beasts.' The beast-comparison — humans tested to see their own animal nature. Hebrews 2:14-15: 'Since therefore the children share in flesh and blood, he himself likewise partook of the same things, that through death he might destroy the one who has the power of death, that is, the devil, and deliver all those who through fear of death were subject to lifelong slavery.' Christ entered the full creaturely limitation — including mortality — not because he was tested and found wanting, but voluntarily, to deliver those who were subject to it. He became what we are in order to make us what he is.</p>",
    "19": "<p>A type: 'For what happens to the children of man and what happens to the beasts is the same; as one dies, so dies the other. They all have the same breath, and man has no advantage over the beasts, for all is vanity.' The same-death-as-beasts observation — human mortality as not qualitatively different from animal death. Hebrews 2:14-17: Christ shared in flesh and blood 'that through death he might destroy the one who has the power of death.' The 'same death as beasts' is the condition Christ entered — fully, without qualification — in order to break it. By dying as a man (sharing the fate Qohelet describes), he made death the site of victory rather than the final word.</p>",
    "20": "<p>A type: 'All go to one place. All are from the dust, and to dust all return.' Dust to dust — the common human fate. John 12:24: 'Truly, truly, I say to you, unless a grain of wheat falls into the earth and dies, it remains alone; but if it dies, it bears much fruit.' Christ submitted to the dust-return explicitly: he was buried, descended into the earth as the grain of wheat. But the grain of wheat that falls into the earth does not remain dust — it rises as a plant bearing many grains. The dust-return that Qohelet sees as the terminus becomes in Christ the planting that precedes the harvest.</p>",
    "21": "<p>A direct connection: 'Who knows whether the spirit of man goes upward and the spirit of the beast goes downward to the earth?' Qohelet's open question about the human spirit's post-death destination. John 3:13: 'No one has ascended into heaven except he who descended from heaven, the Son of Man.' Acts 1:9-11: Christ's bodily ascension is the definitive answer to Qohelet's 'who knows whether the spirit goes upward.' The answer: the Son of Man has ascended, and his ascension is the pledge of the believer's resurrection and ascension (Eph 2:6: God 'raised us up with him and seated us with him in the heavenly places'). The question of 3:21 is answered by the event of Acts 1.</p>",
    "22": "<p>A shadow: 'So I saw that there is nothing better than that a man should rejoice in his work, for that is his lot. Who can bring him to see what will be after him?' The inability to see what comes after — the veil over the future. John 14:2-3: 'In my Father's house are many rooms. If it were not so, would I have told you that I go to prepare a place for you? And if I go and prepare a place for you, I will come again and will take you to myself, that where I am you may be also.' Christ answers Qohelet's 'who can bring him to see what will be' by providing exactly that: a revelation of what is prepared beyond death, and a promise to come again and bring his own to that place. The veil is lifted.</p>"
  },
  "4": {
    "1": "<p>A direct connection: 'Again I saw all the oppressions that are done under the sun. And behold, the tears of the oppressed, and they had no one to comfort them! On the side of their oppressors there was power, and there was no one to comfort them.' The no-comforter for the oppressed — the most grievous deficit Qohelet identifies. John 14:16, 26: 'I will ask the Father, and he will give you another Helper [<em>Parakletos</em>]... the Helper, the Holy Spirit, whom the Father will send in my name.' <em>Parakletos</em> means one called alongside to help, comfort, advocate — precisely what Qohelet observes as missing. The Spirit is the answer to the no-comforter cry: the oppressed who have no earthly comforter are given the divine Comforter, the one who stands alongside in their tears.</p>",
    "2": "<p>A shadow: 'And I thought the dead who are already dead more fortunate than the living who are still alive.' The death-better-than-life thought — the depth of Qohelet's pessimism about earthly existence. Philippians 1:21-23: 'For to me to live is Christ, and to die is gain... I am hard pressed between the two. My desire is to depart and be with Christ, for that is far better.' Paul's 'death is gain' and Qohelet's 'the dead are more fortunate' express similar observations, but from opposite theological positions: Qohelet sees death as escape from oppression; Paul sees death as arrival at Christ. The death-preference is transformed from resignation to anticipation.</p>",
    "3": "<p>A shadow: 'but better than both is he who has not yet been and has not seen the evil deeds that are done under the sun.' The not-yet-born as most fortunate — the extreme form of the pessimism. Revelation 1:18: 'I died, and behold I am alive forevermore, and I have the keys of Death and Hades.' Christ holds the keys to the condition that Qohelet describes. The 'not-yet-born' that Qohelet envies exists only in the realm of potentiality; Christ's resurrection makes it possible for those who have seen evil deeds to enter a life that is better than not having been born — life with him beyond death. The preference for non-existence is answered by the living Lord who has conquered the condition that made existence so grievous.</p>",
    "4": "<p>A shadow: 'Then I saw that all toil and all skill in work come from a man's envy of his neighbor. This also is vanity and a striving after wind.' Envy as the driving force of human competitive achievement — the motive that makes much human industry vanity. Mark 15:10: 'For he perceived that it was out of envy that the chief priests had delivered him up.' The envy Qohelet identifies as the engine of human striving reaches its darkest expression in the envy that drove the crucifixion of Christ. The competitive vanity-dynamic Qohelet observes in human life produced the murder of the one who was truly fruitful and wise.</p>",
    "5": "<p>A shadow: 'The fool folds his hands and eats his own flesh.' The self-consuming laziness of the fool. John 6:53-54: 'Truly, truly, I say to you, unless you eat the flesh of the Son of Man and drink his blood, you have no life in you. Whoever feeds on my flesh and drinks my blood has eternal life.' The fool 'eats his own flesh' — self-consuming, ultimately self-destructive. Christ offers his flesh to be eaten — not self-consumption but the reception of the life-giving gift. The contrast is between the fool turning inward on himself and Christ turning outward in self-giving. The eating of flesh is the same action in both cases; the direction (inward destruction vs. outward gift) is opposite.</p>",
    "6": "<p>A direct connection: 'Better is a handful of quietness than two hands full of toil and a striving after wind.' The handful-of-quietness observation — rest is worth more than frantic productivity. Matthew 11:28-30: 'Come to me, all who labor and are heavy laden, and I will give you rest. Take my yoke upon you, and learn from me, for I am gentle and lowly in heart, and you will find rest for your souls. For my yoke is easy, and my burden is light.' Christ offers the 'handful of quietness' that Qohelet commends as better than two hands of anxious toil. The rest that Qohelet observes to be more valuable than striving is what Christ offers not as a passive absence but as the positive rest of living in his easy yoke.</p>",
    "7": "<p>A shadow: 'Again, I saw vanity under the sun: one person who has no other, either son or brother, yet there is no end to all his toil, and his eyes are never satisfied with riches, so that he never asks, 'For whom am I toiling and depriving myself of pleasure?' This also is vanity and an unhappy business.' The utterly alone toiler — no companion, no heir, endless unsatisfied striving. Mark 15:34: 'My God, my God, why have you forsaken me?' The cry of dereliction is Christ entering the ultimate aloneness — forsaken by the Father at the moment of bearing sin. The solitary toiler of Ecclesiastes 4:7-8 whose eyes are never satisfied and who has no companion is the image Qohelet uses for the vanity of aloneness; Christ entered that very aloneness to bear the abandonment that sin produces.</p>",
    "8": "<p>A theme: 'Two are better than one, because they have a good reward for their toil.' The two-together principle — the better reward of companionship. John 17:21: 'that they may all be one, just as you, Father, are in me, and I in you, that they also may be in us.' Christ's high priestly prayer reframes the two-better-than-one principle as a theological reality: the unity of believers with each other and with the Trinity is the ultimate 'two are better than one.' The companionship that makes toil productive and rewarding is grounded in the Trinitarian communion that Christ shares with the Father and invites his people into.</p>",
    "9": "<p>A shadow: 'For if they fall, one will lift up his fellow. But woe to him who is alone when he falls and has not another to lift him up!' The lifter of the fallen companion. Hebrews 7:25: 'he always lives to make intercession for them' — Christ as the eternal companion who never falls and always intercedes for those who do fall. 1 John 2:1: 'if anyone does sin, we have an advocate with the Father, Jesus Christ the righteous.' The advocate who lifts the fallen is not a human companion but the risen Christ who intercedes perpetually. The 'no one to lift him up' that Qohelet identifies as the tragedy of aloneness is addressed by Christ's permanent advocacy.</p>",
    "10": "<p>A shadow: 'Again, if two lie together, they keep warm, but how can one keep warm alone?' The warmth of companionship — the isolated person cannot maintain warmth. John 10:3-4, 14-16: 'I am the good shepherd. I know my own and my own know me.' The intimate union of shepherd and sheep — the shepherd who calls his own by name, goes before them, and they know his voice — is the NT form of the keeping-warm-together principle. The isolated person who cannot keep warm alone is given the Good Shepherd who dwells with his flock; the Spirit who dwells within (John 14:17: 'he dwells with you and will be in you') is the warmth of companionship internalized.</p>",
    "11": "<p>A shadow: 'And though a man might prevail against one who is alone, two will withstand him — a threefold cord is not quickly broken.' The strength of solidarity — two resist what one cannot; three more so. John 17:21-23: 'that they may all be one, just as you, Father, are in me, and I in you, that they also may be in us... I in them and you in me, that they may become perfectly one.' The threefold cord — Father, Son, Spirit — is the ultimate unbreakable bond; believers woven into this Trinitarian union are not quickly broken. The sociological wisdom of the threefold cord becomes in Christ's prayer the theology of Trinitarian union extended to include the church.</p>",
    "12": "<p>A type: 'Better was a poor and wise youth than an old and foolish king who no longer knew how to take advice.' The poor-and-wise-youth who is better than the established foolish king — the unexpected inversion of power and status. Philippians 2:7-9: 'he emptied himself, by taking the form of a servant, being born in the likeness of men... he humbled himself by becoming obedient to the point of death, even death on a cross. Therefore God has highly exalted him.' The poor-wise-youth who becomes king is a type of Christ: born in poverty and humility (Luke 2:7: no room in the inn; John 1:46: can anything good come out of Nazareth?), rejected by the established authorities, ultimately exalted above every name.</p>",
    "13": "<p>A direct type: 'for he went from prison to the throne, though in his own kingdom he had been born poor.' Prison to throne — the definitive inversion narrative. Philippians 2:8-9: 'he humbled himself by becoming obedient to the point of death, even death on a cross. Therefore God has highly exalted him and bestowed on him the name that is above every name.' Ephesians 4:8-10: 'When he ascended on high he led a host of captives... (in saying, 'He ascended,' what does it mean but that he had also descended into the lower regions, the earth?).' The one who descended to the lowest point (the cross, the grave) is the one who ascended to the highest place — the prison-to-throne trajectory fulfilled in the death-and-resurrection of Christ. This is one of Ecclesiastes' clearest pre-figurations of the incarnation-and-exaltation pattern.</p>",
    "14": "<p>A shadow: 'I saw all the living who move about under the sun, along with that youth who was to stand in the king's place.' The universal following of the new king — all the living follow the one who takes the throne. John 12:32: 'And I, when I am lifted up from the earth, will draw all people to myself.' The drawing-of-all-people to the lifted-up Christ is the fulfillment of the all-the-living-following-the-new-king image. Where Qohelet's youth-king attracts the multitude transiently (and the next generation will not rejoice in him either, v. 16), Christ's drawing is permanent: his 'all people' includes every generation, and the joy of those who come to him is not temporary.</p>",
    "15": "<p>A shadow: 'yet those who come later will not rejoice in him. Surely this also is vanity and a striving after wind.' The transience of popular adulation — even the greatest leader is forgotten by the next generation. John 6:66-68: 'After this many of his disciples turned back and no longer walked with him. So Jesus said to the twelve, 'Do you want to go away as well?' Simon Peter answered him, 'Lord, to whom shall we go? You have the words of eternal life.'' Christ experienced the abandonment Qohelet predicts — disciples turning back (like all popular leaders eventually experiencing declining followers). But Peter's confession breaks the pattern: 'to whom shall we go?' The twelve are the remnant who do not follow the transience-trajectory; their loyalty is based on something other than popular enthusiasm.</p>",
    "16": "<p>A shadow: 'There was no end to all the people, all of whom he led. Yet those who come later will not rejoice in him. Surely this also is vanity and a striving after wind.' The final vanity verdict on even the most successful human leader — all popular movements are temporary. John 15:16: 'You did not choose me, but I chose me and appointed you that you should go and bear fruit and that your fruit should abide.' The relationship between Christ and his disciples reverses the leader-popularity dynamic: they are not followers who chose him and will eventually stop rejoicing; they are chosen, appointed, and their fruit is designed to 'abide' — to be permanent. The transience that attaches to every human leader does not attach to Christ, whose chosen ones bear abiding fruit.</p>"
  }
}

def main():
    c = load_comm('mkt-christ', 'ecclesiastes')
    merge_comm(c, DATA)
    save_comm('mkt-christ', 'ecclesiastes', c)
    total = sum(len(v) for v in DATA.values())
    print(f'ecclesiastes mkt-christ: added {total} verses across ch1-4')

if __name__ == '__main__':
    main()
